-- Dropdown/enum header definitions
CREATE TABLE IF NOT EXISTS constant_header (
    id                                   VARCHAR(60)   NOT NULL,
    caption                              VARCHAR(80)   NOT NULL,
    CONSTRAINT constant_header_pk PRIMARY KEY (id)
);

-- Dropdown/enum values for each constant header
CREATE TABLE IF NOT EXISTS constant_value (
    constant_id                          VARCHAR(60)   NOT NULL,
    value                                VARCHAR(80)   NOT NULL,
    caption                              VARCHAR(80)   NOT NULL,
    CONSTRAINT constant_value_pk PRIMARY KEY (constant_id, value)
);

-- Maps constant domains to table columns
CREATE TABLE IF NOT EXISTS constant_lookup (
    constant_id                          VARCHAR(60)   NOT NULL,
    table_name                           VARCHAR(60)   NOT NULL,
    column_name                          VARCHAR(60)   NOT NULL,
    CONSTRAINT constant_lookup_pk PRIMARY KEY (constant_id, table_name, column_name)
);

-- Controls FK display behavior in the UI
CREATE TABLE IF NOT EXISTS foreign_key_lookup (
    constraint_name                      VARCHAR(60)   NOT NULL,
    lookup_style                         CHAR(1)       NOT NULL,
    display_column                       VARCHAR(60)   NOT NULL,
    CONSTRAINT foreign_key_lookup_pk PRIMARY KEY (constraint_name)
);

-- Metadata-driven REST API definitions
CREATE TABLE IF NOT EXISTS rest_api_header (
    id                                   VARCHAR(80)   NOT NULL,
    version                              VARCHAR(20)   NOT NULL DEFAULT 'v1',
    master_table                         VARCHAR(60)   NOT NULL,
    is_active                            BOOLEAN       NOT NULL DEFAULT TRUE,
    CONSTRAINT rest_api_header_pk PRIMARY KEY (id)
);

-- Child relations for REST APIs
CREATE TABLE IF NOT EXISTS rest_api_child (
    api_id                               VARCHAR(80)   NOT NULL,
    seq                                  INTEGER       NOT NULL,
    parent_seq                           INTEGER       NOT NULL DEFAULT 0,
    constraint_name                      VARCHAR(60)   NOT NULL,
    CONSTRAINT rest_api_child_pk PRIMARY KEY (api_id, seq)
);
CREATE INDEX IF NOT EXISTS idx_rest_api_child_fk ON rest_api_child(constraint_name);

-- Report definitions
CREATE TABLE IF NOT EXISTS rest_report_header (
    id                                   VARCHAR(80)   NOT NULL,
    version                              VARCHAR(20)   NOT NULL DEFAULT 'v1',
    query_name                           VARCHAR(60)   NOT NULL,
