    constant_id                          VARCHAR(60)  ,
    CONSTRAINT rest_report_param_pk PRIMARY KEY (report_id, seq)
);

-- Maps tables to their PostgreSQL sequences
CREATE TABLE IF NOT EXISTS table_sequence_usage (
