    monthly_cost                         NUMERIC(18,2) NOT NULL,
    currency                             CHAR(3)       NOT NULL DEFAULT 'USD',
    billing_cycle                        CHAR(1)       NOT NULL DEFAULT 'M',
    term_count                           INTEGER       NOT NULL DEFAULT 1,
    term_type                            CHAR(1)       NOT NULL DEFAULT 'M',
    description                          VARCHAR(255) ,
    CONSTRAINT subscription_addon_pk PRIMARY KEY (id)
);

-- Single-use, TTL-bounded nonces (OAuth connect-state, JWT handoff). Natural key, no sequence.
CREATE TABLE IF NOT EXISTS auth_nonce (
    nonce                                VARCHAR(64)   NOT NULL,
    purpose                              VARCHAR(20)   NOT NULL,
    payload                              TEXT          NOT NULL,
    created_at                           TIMESTAMP     NOT NULL DEFAULT CURRENT_TIMESTAMP,
    CONSTRAINT auth_nonce_pk PRIMARY KEY (nonce)
);

-- Active plan subscriptions per business partner
CREATE TABLE IF NOT EXISTS partner_plan_subscription (
    partner_id                           BIGINT        NOT NULL,
    plan_id                              VARCHAR(20)   NOT NULL,
    begda                                TIMESTAMP     NOT NULL,
    endda                                TIMESTAMP    ,
    monthly_cost                         NUMERIC(18,2) NOT NULL,
    currency                             CHAR(3)       NOT NULL,
    status                               CHAR(1)       NOT NULL,
    auto_renew                           BOOLEAN       NOT NULL DEFAULT TRUE,
    provider_subscription_id             VARCHAR(64)  ,
    billing_cycle                        CHAR(1)      ,
    term_count                           INTEGER      ,
    term_type                            CHAR(1)      ,
    amount_minor                         BIGINT       ,
    renewal_date                         TIMESTAMP    ,
    next_charge_date                     TIMESTAMP    ,
    cancelled_at                         TIMESTAMP    ,
    effective_cancel_date                TIMESTAMP    ,
    trial_end                            TIMESTAMP    ,
    seats                                INTEGER      ,
    CONSTRAINT partner_plan_subscription_pk PRIMARY KEY (partner_id, plan_id, begda)
);
CREATE INDEX IF NOT EXISTS idx_partner_plan_subscription_provider_sub ON partner_plan_subscription(provider_subscription_id);

-- Active add-on subscriptions per business partner
CREATE TABLE IF NOT EXISTS partner_addon_subscription (
    partner_id                           BIGINT        NOT NULL,
    addon_id                             VARCHAR(20)   NOT NULL,
    auto_increase                        BOOLEAN       NOT NULL DEFAULT FALSE,
    begda                                TIMESTAMP     NOT NULL,
    endda                                TIMESTAMP    ,
    monthly_cost                         NUMERIC(18,2) NOT NULL,
    currency                             CHAR(3)       NOT NULL,
    status                               CHAR(1)       NOT NULL,
    auto_renew                           BOOLEAN       NOT NULL DEFAULT TRUE,
    billing_cycle                        CHAR(1)      ,
    term_count                           INTEGER      ,
    term_type                            CHAR(1)      ,
    amount_minor                         BIGINT       ,
    renewal_date                         TIMESTAMP    ,
    next_charge_date                     TIMESTAMP    ,
    CONSTRAINT partner_addon_subscription_pk PRIMARY KEY (partner_id, addon_id, begda)
);

-- Resource usage tracking for quota enforcement
CREATE TABLE IF NOT EXISTS usage_ledger (
    partner_id                           BIGINT        NOT NULL,
    usage_time                           TIMESTAMP     NOT NULL DEFAULT CURRENT_TIMESTAMP,
    resource_name                        VARCHAR(50)   NOT NULL,
    amount                               BIGINT        NOT NULL,
    notes                                VARCHAR(255) ,
    CONSTRAINT usage_ledger_pk PRIMARY KEY (partner_id, usage_time)
);
CREATE INDEX IF NOT EXISTS idx_usage_ledger_quota ON usage_ledger(partner_id, resource_name, usage_time);

-- Raw inbound payment provider webhooks — idempotency + audit
CREATE TABLE IF NOT EXISTS payment_webhook_log (
    id                                   BIGINT        NOT NULL,
    provider                             VARCHAR(30)   NOT NULL,
    event_id                             VARCHAR(255)  NOT NULL,
    event_type                           VARCHAR(100)  NOT NULL,
    processing_status                    CHAR(1)       NOT NULL DEFAULT 'R',
    error_message                        TEXT         ,
    raw_payload                          TEXT         ,
    received_at                          TIMESTAMP     NOT NULL DEFAULT CURRENT_TIMESTAMP,
    processed_at                         TIMESTAMP    ,
    CONSTRAINT payment_webhook_log_pk PRIMARY KEY (id)
);
CREATE UNIQUE INDEX IF NOT EXISTS payment_webhook_log_uq ON payment_webhook_log(provider, event_id);

CREATE SEQUENCE IF NOT EXISTS payment_webhook_log_seq INCREMENT BY 1 START WITH 1;
INSERT INTO table_sequence_usage (table_name, column_name, sequence_name) VALUES ('payment_webhook_log', 'id', 'payment_webhook_log_seq') ON CONFLICT DO NOTHING;

-- Stored payment methods per business partner (provider customer tokens)
CREATE TABLE IF NOT EXISTS payment_method (
    id                                   BIGINT        NOT NULL,
    partner_id                           BIGINT        NOT NULL,
    provider                             VARCHAR(30)   NOT NULL,
    provider_token                       VARCHAR(255)  NOT NULL,
    method_type                          VARCHAR(20)   NOT NULL,
    is_default                           BOOLEAN       NOT NULL DEFAULT FALSE,
    created_at                           TIMESTAMP     NOT NULL DEFAULT CURRENT_TIMESTAMP,
    CONSTRAINT payment_method_pk PRIMARY KEY (id)
);
CREATE INDEX IF NOT EXISTS idx_payment_method_default ON payment_method(partner_id, is_default);

CREATE SEQUENCE IF NOT EXISTS payment_method_seq INCREMENT BY 1 START WITH 1;
INSERT INTO table_sequence_usage (table_name, column_name, sequence_name) VALUES ('payment_method', 'id', 'payment_method_seq') ON CONFLICT DO NOTHING;

-- Completed/failed/refunded payment transactions per partner
CREATE TABLE IF NOT EXISTS payment_record (
    id                                   BIGINT        NOT NULL,
    partner_id                           BIGINT       ,
    provider                             VARCHAR(30)   NOT NULL,
    provider_payment_id                  VARCHAR(255) ,
    provider_event_type                  VARCHAR(100) ,
    amount                               NUMERIC(18,2) NOT NULL,
    currency                             CHAR(3)       NOT NULL,
    plan_id                              VARCHAR(20)  ,
    invoice_id                           BIGINT       ,
    payment_status                       CHAR(1)       NOT NULL,
    paid_at                              TIMESTAMP    ,
    raw_payload                          TEXT         ,
    created_at                           TIMESTAMP     NOT NULL DEFAULT CURRENT_TIMESTAMP,
    CONSTRAINT payment_record_pk PRIMARY KEY (id)
);
CREATE INDEX IF NOT EXISTS idx_payment_record_partner ON payment_record(partner_id, paid_at);

CREATE SEQUENCE IF NOT EXISTS payment_record_seq INCREMENT BY 1 START WITH 1;
INSERT INTO table_sequence_usage (table_name, column_name, sequence_name) VALUES ('payment_record', 'id', 'payment_record_seq') ON CONFLICT DO NOTHING;

-- Per (user, partner) bank account details for out-bound payouts.
-- Owned by keel/payout. Raw routing details live with the provider
-- (Airwallex / Stripe Connect / Wise); this row carries only the
-- provider handle plus tax/correspondence metadata.
CREATE TABLE IF NOT EXISTS user_bank_info (
    user_id                              BIGINT        NOT NULL,
    partner_id                           BIGINT        NOT NULL,
    country_code                         CHAR(2)       NOT NULL,
    currency                             CHAR(3)       NOT NULL,
    account_holder_name                  VARCHAR(200)  NOT NULL,
    billing_address                      TEXT          NOT NULL,
    tax_id_type                          CHAR(1)       NOT NULL,
    tax_id_encrypted                     BYTEA         NOT NULL,
    provider                             CHAR(2)       NOT NULL,
    provider_account_id                  VARCHAR(100) ,
    provider_agreement                   BOOLEAN       NOT NULL DEFAULT FALSE,
    provider_onboarded_at                TIMESTAMP    ,
    created_at                           TIMESTAMP     NOT NULL DEFAULT CURRENT_TIMESTAMP,
    updated_at                           TIMESTAMP     NOT NULL DEFAULT CURRENT_TIMESTAMP,
    CONSTRAINT user_bank_info_pk PRIMARY KEY (user_id, partner_id)
);
CREATE INDEX IF NOT EXISTS idx_user_bank_info_partner ON user_bank_info(partner_id);

-- Saved payment methods for end users (cards, wallets, bank accounts).
-- Distinct from `payment_method`, which is partner-scoped for SaaS
-- billing — this row is per (user_id), the consumer cards a user has
-- on file for in-bound payments. provider_token is the provider's
-- reusable handle (Stripe PaymentMethod id, SetupIntent id, etc.);
-- raw card numbers / IBANs / SWIFT never land here.
CREATE TABLE IF NOT EXISTS user_payment_method (
    id                                   BIGINT        NOT NULL,
    user_id                              BIGINT        NOT NULL,
    method_type                          VARCHAR(20)   NOT NULL,
    provider                             VARCHAR(30)   NOT NULL,
    provider_token                       VARCHAR(255)  NOT NULL,
    last_four                            VARCHAR(4)   ,
    brand                                VARCHAR(20)  ,
    expiry_month                         SMALLINT     ,
    expiry_year                          SMALLINT     ,
    currency                             CHAR(3)       NOT NULL DEFAULT 'USD',
    is_default                           BOOLEAN       NOT NULL DEFAULT FALSE,
    created_at                           TIMESTAMP     NOT NULL DEFAULT CURRENT_TIMESTAMP,
    CONSTRAINT user_payment_method_pk PRIMARY KEY (id)
);
CREATE INDEX IF NOT EXISTS idx_user_payment_method_user ON user_payment_method(user_id, is_default);

CREATE SEQUENCE IF NOT EXISTS user_payment_method_seq INCREMENT BY 1 START WITH 1;
INSERT INTO table_sequence_usage (table_name, column_name, sequence_name) VALUES ('user_payment_method', 'id', 'user_payment_method_seq') ON CONFLICT DO NOTHING;

-- Per-table custom actions surfaced as buttons in CRUD UIs. Each row
-- registers ONE action; the downstream application must also (a) seed
-- the matching authorization_object + authorization_object_action rows
-- so roles can grant access, and (b) register an HTTP handler at the
-- conventional URL POST /<rest_prefix>/<table_name>/<action_name>.
-- 
-- authorization_object.id mirrors the uppercased table name and
-- authorization_object_action.action mirrors the uppercased action_name
-- — gives each table its own action namespace so the same action name
-- ('assign', 'enable', 'calculate') can mean different things on
-- different tables without a shared auth dimension.
-- 
-- record_specific=TRUE  → button renders next to per-row edit/delete.
-- record_specific=FALSE → button renders next to the "New Record"
--                         control at the table-level toolbar.
-- 
-- Reserved action_name values that collide with generic CRUD subpaths
-- (list / get / post / delete / get-paginated) are rejected at REST
-- service boot.
CREATE TABLE IF NOT EXISTS table_action (
    table_name                           VARCHAR(80)   NOT NULL,
    action_name                          VARCHAR(30)   NOT NULL,
    caption                              VARCHAR(80)   NOT NULL,
    icon                                 VARCHAR(40)  ,
    record_specific                      BOOLEAN       NOT NULL DEFAULT FALSE,
    action_kind                          CHAR(1)       NOT NULL DEFAULT 'P',
    method_name                          VARCHAR(80)  ,
    display_order                        SMALLINT      NOT NULL DEFAULT 10,
    confirm_message                      VARCHAR(200) ,
    CONSTRAINT table_action_pk PRIMARY KEY (table_name, action_name)
);
CREATE INDEX IF NOT EXISTS idx_table_action_table ON table_action(table_name);

-- Billing invoices per partner (provider-issued or self-scheduled)
CREATE TABLE IF NOT EXISTS invoice (
    id                                   BIGINT        NOT NULL,
    partner_id                           BIGINT        NOT NULL,
    invoice_number                       VARCHAR(30)   NOT NULL,
    status                               CHAR(1)       NOT NULL DEFAULT 'D',
    subtotal                             NUMERIC(18,2) NOT NULL,
    tax                                  NUMERIC(18,2) NOT NULL DEFAULT 0.00,
    total                                NUMERIC(18,2) NOT NULL,
    total_minor                          BIGINT        NOT NULL DEFAULT 0,
    currency                             CHAR(3)       NOT NULL DEFAULT 'USD',
    issued_at                            TIMESTAMP     NOT NULL DEFAULT CURRENT_TIMESTAMP,
    due_at                               TIMESTAMP    ,
    paid_at                              TIMESTAMP    ,
    pdf_storage_path                     VARCHAR(500) ,
    provider_invoice_id                  VARCHAR(255) ,
    provider_charge_id                   VARCHAR(255) ,
    attempt_count                        INTEGER       NOT NULL DEFAULT 0,
    next_attempt_at                      TIMESTAMP    ,
    last_error                           TEXT         ,
    CONSTRAINT invoice_pk PRIMARY KEY (id)
);
CREATE UNIQUE INDEX IF NOT EXISTS idx_invoice_number ON invoice(invoice_number);
CREATE INDEX IF NOT EXISTS idx_invoice_partner ON invoice(partner_id);

CREATE SEQUENCE IF NOT EXISTS invoice_seq INCREMENT BY 1 START WITH 1;
INSERT INTO table_sequence_usage (table_name, column_name, sequence_name) VALUES ('invoice', 'id', 'invoice_seq') ON CONFLICT DO NOTHING;

-- Line items for an invoice
CREATE TABLE IF NOT EXISTS invoice_line (
    invoice_id                           BIGINT        NOT NULL,
    seq                                  INTEGER       NOT NULL,
    description                          VARCHAR(200)  NOT NULL,
    quantity                             INTEGER       NOT NULL DEFAULT 1,
    unit_price                           NUMERIC(18,2) NOT NULL,
    amount                               NUMERIC(18,2) NOT NULL,
    CONSTRAINT invoice_line_pk PRIMARY KEY (invoice_id, seq)
);

-- Partner ↔ provider-customer token, one row per (partner, provider). Its own
-- table (not a method_type='customer' row in payment_method) so payment_method
-- holds only real chargeable methods. Used for billing-portal sessions and
-- recurring-invoice attribution (the reverse token→partner lookup).
CREATE TABLE IF NOT EXISTS partner_billing_customer (
    partner_id                           BIGINT        NOT NULL,
    provider                             VARCHAR(30)   NOT NULL,
    customer_token                       VARCHAR(255)  NOT NULL,
    created_at                           TIMESTAMP     NOT NULL DEFAULT CURRENT_TIMESTAMP,
    CONSTRAINT partner_billing_customer_pk PRIMARY KEY (partner_id, provider)
);
CREATE UNIQUE INDEX IF NOT EXISTS idx_partner_billing_customer_token ON partner_billing_customer(provider, customer_token);

-- Transactional outbox — events captured in the same tx as a domain write, then drained by a lease worker for reliable at-least-once delivery
CREATE TABLE IF NOT EXISTS outbox_event (
    id                                   BIGINT        NOT NULL,
    partner_id                           BIGINT       ,
    aggregate_type                       VARCHAR(64)   NOT NULL,
    aggregate_id                         VARCHAR(128)  NOT NULL,
    event_type                           VARCHAR(64)   NOT NULL,
    payload                              TEXT         ,
    status                               CHAR(1)       NOT NULL DEFAULT 'P',
    attempts                             INTEGER       NOT NULL DEFAULT 0,
    available_at                         TIMESTAMP     NOT NULL DEFAULT CURRENT_TIMESTAMP,
    lease_until                          TIMESTAMP    ,
    lease_token                          BIGINT       ,
    last_error                           TEXT         ,
    created_at                           TIMESTAMP     NOT NULL DEFAULT CURRENT_TIMESTAMP,
    updated_at                           TIMESTAMP     NOT NULL DEFAULT CURRENT_TIMESTAMP,
    CONSTRAINT outbox_event_pk PRIMARY KEY (id)
);
CREATE INDEX IF NOT EXISTS idx_outbox_drain ON outbox_event(status, available_at);
CREATE INDEX IF NOT EXISTS idx_outbox_aggregate ON outbox_event(aggregate_type, aggregate_id);

CREATE SEQUENCE IF NOT EXISTS outbox_event_seq INCREMENT BY 1 START WITH 1;
INSERT INTO table_sequence_usage (table_name, column_name, sequence_name) VALUES ('outbox_event', 'id', 'outbox_event_seq') ON CONFLICT DO NOTHING;

-- Catalog of runtime configuration flags loaded into common.BaseConfig at startup. Non-secret values only; store a secret NAME here, never secret material.
CREATE TABLE IF NOT EXISTS application_config_flag (
    id                                   VARCHAR(80)   NOT NULL,
    data_type                            VARCHAR(20)   NOT NULL DEFAULT 'string',
    needs_restart                        BOOLEAN       NOT NULL DEFAULT FALSE,
    default_value                        TEXT         ,
    description                          TEXT         ,
    CONSTRAINT application_config_flag_pk PRIMARY KEY (id)
);

-- Per-node assigned values for application_config_flag. node_id identifies the runtime node/process (matched against --node_id). Most single-node deployments use 0; multi-node deployments assign values per node. Missing rows fall back to application_config_flag.default_value.
CREATE TABLE IF NOT EXISTS application_config_value (
    node_id                              INTEGER       NOT NULL DEFAULT 0,
    flag_id                              VARCHAR(80)   NOT NULL,
    assigned_value                       TEXT         ,
    CONSTRAINT application_config_value_pk PRIMARY KEY (node_id, flag_id)
);

